@startuml

class StaticFactory {
  {static} +produce() : produce
}

class ConcreteProduct1 {
  +produce() : void
}

class ConcreteProduct2 {
  +produce() : void
}

abstract class Product {
  +void produce()
}

StaticFactory ..> ConcreteProduct1
StaticFactory ..> ConcreteProduct2
ConcreteProduct1 --|> Product
ConcreteProduct2 --|> Product

@enduml
